const pendingFull = Number((context.panel.elements.find(function(e){return e.id==='pending_full_reindex';})||{}).value || 0);
if (pendingFull > 0) {
  context.grafana.notifyWarning(['Full reindex blocked', 'A full-reindex job is already pending or running. Wait for it to finish before triggering another.']);
  return;
}
if (!window.confirm('Reindex ALL realms?\n\nThis kicks off an indexing job for every realm on the server and can take a long time.')) { return; }
(async () => {
try {
  const r = await fetch(${realm_server:doublequote} + '_grafana-full-reindex', { method: 'POST', headers: { 'Authorization': 'Bearer ' + ${grafana_secret:doublequote} } });
  if (r.ok) {
    context.grafana.notifySuccess(['Full reindex queued', 'Started reindex of all realms.']);
    if (typeof context.grafana.refresh === 'function') { context.grafana.refresh(); }
  } else {
    const txt = await r.text();
    context.grafana.notifyError(['Full reindex failed', 'HTTP ' + r.status + ': ' + txt]);
  }
} catch (err) {
  context.grafana.notifyError(['Full reindex failed', String(err)]);
}

})().catch(function (err) { console.error('operator action handler error:', err); });
